      "code": "export const meta = {\n  slug: 'wave',\n  title: 'Animated Wave',\n  description: 'A bright sine wave animated by time and custom uniforms.',\n  files: ['meta.ts', 'example.ts', 'shader.wgsl'],\n} as const;\n"
